import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function AddTest() {
  const [title, setTitle] = useState("");
  const [courseId, setCourseId] = useState("");
  const [duration, setDuration] = useState("");
  const [questions, setQuestions] = useState([
    { text: "", options: ["", "", "", ""], correctAnswer: "" },
  ]);
  const [courses, setCourses] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();

  useEffect(() => {
    if (user?.role === "teacher") {
      fetch(`http://localhost:3001/courses?teacherId=${user.id}`)
        .then((res) => res.json())
        .then((data) => setCourses(data))
        .catch((error) => toast.error("Ошибка загрузки курсов"));
    }
  }, [user]);

  function handleQuestionChange(index, field, value) {
    const newQuestions = [...questions];
    if (field === "text" || field === "correctAnswer") {
      newQuestions[index][field] = value;
    } else if (field.startsWith("option")) {
      const optionIndex = parseInt(field.split("-")[1]);
      newQuestions[index].options[optionIndex] = value;
    }
    setQuestions(newQuestions);
  }

  function addQuestion() {
    setQuestions([
      ...questions,
      { text: "", options: ["", "", "", ""], correctAnswer: "" },
    ]);
  }

  function removeQuestion(index) {
    if (questions.length > 1) {
      setQuestions(questions.filter((_, i) => i !== index));
    }
  }

  async function handleSubmit(e) {
    e.preventDefault();
    if (!title || !courseId || !duration) {
      toast.error("Заполните все обязательные поля!");
      return;
    }

    for (const question of questions) {
      if (
        !question.text ||
        question.options.some((opt) => !opt) ||
        !question.correctAnswer ||
        !question.options.includes(question.correctAnswer)
      ) {
        toast.error(
          "Все вопросы должны иметь текст, 4 варианта ответа и правильный ответ!"
        );
        return;
      }
    }

    const newTest = {
      title,
      courseId: parseInt(courseId),
      duration: parseInt(duration),
      questions: questions.map((q, index) => ({
        id: index + 1,
        text: q.text,
        options: q.options,
        correctAnswer: q.correctAnswer,
      })),
    };

    try {
      const response = await fetch("http://localhost:3001/tests", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(newTest),
      });

      if (response.ok) {
        const course = courses.find((c) => c.id === parseInt(courseId));
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: `Тест "${title}" добавлен для курса "${course.name}".`,
            createdAt: new Date().toISOString(),
          }),
        });
        toast.success("Тест успешно добавлен!");
        navigate("/courses");
      } else {
        toast.error("Не удалось добавить тест");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при добавлении теста");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-8">
          <div className="card shadow">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Добавить тест</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="title" className="form-label">
                    Название теста
                  </label>
                  <input
                    type="text"
                    id="title"
                    className="form-control"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="course" className="form-label">
                    Курс
                  </label>
                  <select
                    id="course"
                    className="form-select"
                    value={courseId}
                    onChange={(e) => setCourseId(e.target.value)}
                    required
                  >
                    <option value="">-- Выберите курс --</option>
                    {courses.map((course) => (
                      <option key={course.id} value={course.id}>
                        {course.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="mb-3">
                  <label htmlFor="duration" className="form-label">
                    Длительность (в минутах)
                  </label>
                  <input
                    type="number"
                    id="duration"
                    className="form-control"
                    value={duration}
                    onChange={(e) => setDuration(e.target.value)}
                    min="1"
                    required
                  />
                </div>
                <h4 className="mb-3">Вопросы</h4>
                {questions.map((question, index) => (
                  <div key={index} className="card mb-3">
                    <div className="card-body">
                      <div className="mb-3">
                        <label
                          htmlFor={`question-${index}`}
                          className="form-label"
                        >
                          Вопрос {index + 1}
                        </label>
                        <input
                          type="text"
                          id={`question-${index}`}
                          className="form-control"
                          value={question.text}
                          onChange={(e) =>
                            handleQuestionChange(index, "text", e.target.value)
                          }
                          required
                        />
                      </div>
                      {question.options.map((option, optIndex) => (
                        <div key={optIndex} className="mb-3">
                          <label
                            htmlFor={`option-${index}-${optIndex}`}
                            className="form-label"
                          >
                            Вариант {optIndex + 1}
                          </label>
                          <input
                            type="text"
                            id={`option-${index}-${optIndex}`}
                            className="form-control"
                            value={option}
                            onChange={(e) =>
                              handleQuestionChange(
                                index,
                                `option-${optIndex}`,
                                e.target.value
                              )
                            }
                            required
                          />
                        </div>
                      ))}
                      <div className="mb-3">
                        <label
                          htmlFor={`correct-${index}`}
                          className="form-label"
                        >
                          Правильный ответ
                        </label>
                        <input
                          type="text"
                          id={`correct-${index}`}
                          className="form-control"
                          value={question.correctAnswer}
                          onChange={(e) =>
                            handleQuestionChange(
                              index,
                              "correctAnswer",
                              e.target.value
                            )
                          }
                          required
                        />
                      </div>
                      {questions.length > 1 && (
                        <button
                          type="button"
                          className="btn btn-danger btn-sm"
                          onClick={() => removeQuestion(index)}
                        >
                          Удалить вопрос
                        </button>
                      )}
                    </div>
                  </div>
                ))}
                <button
                  type="button"
                  className="btn btn-secondary mb-3"
                  onClick={addQuestion}
                >
                  Добавить вопрос
                </button>
                <button type="submit" className="btn btn-primary w-100">
                  Сохранить тест
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AddTest;
